const uiDiv = document.getElementById('ui') as HTMLDivElement;

export const canvas = document.createElement('canvas');
export const ctx = canvas.getContext('2d')!;
uiDiv.appendChild(canvas);

function resize() {
  // Match the canvas's CSS size to the viewport
  canvas.style.width = innerWidth + 'px';
  canvas.style.height = innerHeight + 'px';

  // Set the internal pixel dimensions of the canvas
  canvas.width = innerWidth * devicePixelRatio;
  canvas.height = innerHeight * devicePixelRatio;

  // Reset any previous transform and apply the correct scaling.
  // Using setTransform avoids compounding the scale on repeated resizes.
  ctx.setTransform(devicePixelRatio, 0, 0, devicePixelRatio, 0, 0);
}

window.addEventListener('resize', resize);
resize();

const STATUS_LINGER_TIME_MS = 2_000;
let status = '';
let statusTime = 0;

export function showStatus(msg: string) {
  status = msg;
  statusTime = Date.now();
}

const STATUS_PADDING_X = 10;
const STATUS_PADDING_Y = 6;

export function renderStatus() {
  if (status.length > 0 && Date.now() - statusTime < STATUS_LINGER_TIME_MS) {
    ctx.save();
    ctx.font = '16px monospace';
    const { width } = ctx.measureText(status);
    const textX = innerWidth - width - 20;
    const textY = innerHeight - 20;
    const boxX = textX - STATUS_PADDING_X;
    const boxY = textY - 14 - STATUS_PADDING_Y;
    const boxW = width + STATUS_PADDING_X * 2;
    const boxH = 16 + STATUS_PADDING_Y * 2;
    ctx.fillStyle = 'rgba(255, 255, 255, 0.75)';
    ctx.beginPath();
    ctx.roundRect(boxX, boxY, boxW, boxH, 4);
    ctx.fill();
    ctx.fillStyle = '#00a';
    ctx.fillText(status, textX, textY);
    ctx.restore();
  }
}
