import { parse } from './compiler';
import { PatchSettings } from './types';

const DEFAULT_EFFECTS_CODE = `
left = input
right = input
`;

const DEFAULT_SETTINGS: PatchSettings = {
  mode: 'mpe',
  mono: false,
  octave: 0,
  A: 0,
  B: 0,
  C: 0,
  D: 0,
  E: 0,
  F: 0,
  G: 0,
  H: 0,
};

export class Patch {
  settings: PatchSettings;

  constructor(
    public name: string,
    settings: Partial<PatchSettings>,
    public voiceCode: string,
    public effectsCode: string = DEFAULT_EFFECTS_CODE
  ) {
    // check for errors in the code
    parse(voiceCode);
    parse(effectsCode);

    this.settings = {
      ...DEFAULT_SETTINGS,
      ...settings,
    };
  }
}

