import * as ohm from 'ohm-js';
import { PARAM_NAMES } from './constants';
import { Signal } from './signal';
import { inlinedModules } from './inlined-modules';
import { builtInSignals } from './built-in-signals';
import { msynthLib as lib } from './msynth-lib';
import { Module } from './module';
import { isMode, isOctave, MODES, OCTAVES, PatchSettings } from './types';

export class CompilerErrors {
  constructor(readonly errors: CompilerError[]) {}
}

class CompilerError extends Error {
  constructor(
    message: string,
    readonly interval: ohm.Interval
  ) {
    super(message);
  }
}

export const grammar = ohm.grammar(String.raw`
  MSynth {
    Prog = Decl+

    Decl  (a declaration)
      = ident "=" Expr

    Expr = ArrowExpr

    ArrowExpr
      = ArrowExpr ">>" ident Args?  -- send
      | AddExpr

    AddExpr
      = AddExpr "+" MulExpr  -- plus
      | AddExpr "-" MulExpr  -- minus
      | MulExpr

    MulExpr
      = MulExpr "*" NegExpr  -- times
      | MulExpr "/" NegExpr  -- div
      | MulExpr "%" NegExpr  -- mod
      | NegExpr

    NegExpr
      = "-" NegExpr  -- neg
      | SendExpr

    SendExpr
      = SendExpr ~(ident "=") ident Args?  -- send
      | PriExpr

    PriExpr
      = ident Args    -- call
      | ident         -- ref
      | number        -- num
      | "(" Expr ")"  -- par

    Args = "(" ListOf<Arg, ","> ")"

    Arg  (an argument)
      = ident ":" Expr  -- nameAndExpr
      | ident           -- nameIsExpr

    ident  (an identifier)
      = ~keyword "$"? letter alnum*

    number  (a number)
      = digit* "." digit+  -- fract
      | digit+             -- whole

    keyword = def | this
    def = "def" ~alnum
    this = "this" ~alnum

    space += "//" (~"\n" any)*  -- comment
  }
`);

interface RefInfo {
  params: number[];
  builtins: string[];
}

abstract class ANode {
  constructor(readonly interval: ohm.Interval) {}
  abstract addRefs(refs: Set<string>): void;
}

interface Setting {
  name: string;
  nameSource: ohm.Interval;
  value: any;
  valueSource: ohm.Interval;
}

class Prog extends ANode {
  constructor(
    readonly decls: Decl[],
    interval: ohm.Interval
  ) {
    super(interval);
  }

  checkDuplicateDeclarations(errors: CompilerError[]) {
    const declared = new Set<string>();
    for (const d of this.decls) {
      if (declared.has(d.name)) {
        errors.push(new CompilerError(`duplicate declaration of signal ${d.name}`, d.interval));
      } else {
        declared.add(d.name);
      }
    }
  }

  checkCalls(errors: CompilerError[], aiModules: Record<string, Module<any>>) {
    for (const decl of this.decls) {
      decl.checkCalls(errors, aiModules);
    }
  }

  checkRefs(errors: CompilerError[]): RefInfo {
    for (const decl of this.decls) {
      decl.checkRefs(this.decls, errors);
    }

    const refs = new Set<string>();
    this.addRefs(refs);

    const params = new Set<number>();
    const builtins = new Set<string>();
    for (const name of refs) {
      const n = getParamNum(name);
      if (n !== null) {
        params.add(n);
      } else if (PARAM_NAMES.has(name)) {
        params.add(PARAM_NAMES.get(name)!);
      } else if (builtInSignals.hasOwnProperty(name)) {
        builtins.add(name);
      }
    }

    return {
      params: [...params],
      builtins: [...builtins],
    };
  }

  override addRefs(refs: Set<string>) {
    for (const decl of this.decls) {
      decl.addRefs(refs);
    }
  }

  trans(refs: RefInfo): string {
    const haveSignal = (name: string) => this.decls.some(d => d.name === name);
    let outputs: string[];
    if (haveSignal('left') && haveSignal('right')) {
      outputs = ['__left', '__right'];
    } else if (haveSignal('out')) {
      outputs = ['__out'];
    } else {
      outputs = ['Signal.scalar(0)'];
    }
    return `(() => {
      ${refs.params.map(n => `const __param${n} = Signal.new((synth) => synth.params[${n}]);`).join('\n')}
      ${[...PARAM_NAMES.entries()]
        .filter(([name, n]) => refs.params.includes(n))
        .map(([name, n]) => `const __${name} = __param${n};`)
        .join('\n')}
      ${refs.builtins.map(name => `const __${name} = __.${name}();`).join('\n')}
      ${this.decls.map(d => `let __${d.name};`).join('\n')}
      ${this.decls.map(d => d.trans()).join('\n')}
      ${this.decls.map(d => `__${d.name} = __${d.name}.force();`).join('\n')}
      return [${outputs.join(', ')}];
    })()`;
  }
}

class Decl extends ANode {
  constructor(
    readonly name: string,
    readonly rhs: AExpr,
    interval: ohm.Interval
  ) {
    super(interval);
  }

  checkCalls(errors: CompilerError[], aiModules: Record<string, Module<any>>) {
    this.rhs.checkCalls(errors, aiModules);
  }

  override addRefs(refs: Set<string>) {
    this.rhs.addRefs(refs);
  }

  checkRefs(allDecls: Decl[], errors: CompilerError[]) {
    this.rhs.checkRefs(allDecls, errors);
  }

  trans() {
    const signals: string[] = [];
    const expr = this.rhs.trans('signal', signals);
    const signal =
      signals.length === 0
        ? expr
        : `{
      ${signals.map((code, idx) => `const tmp${idx} = ${code};`).join('\n')}
      return ${expr};
    }`;
    return `__${this.name} = lazy(() => ${signal});`;
  }
}

abstract class AExpr extends ANode {
  constructor(
    interval: ohm.Interval,
    readonly children: AExpr[] = []
  ) {
    super(interval);
  }

  checkRefs(allDecls: Decl[], errors: CompilerError[]) {
    for (const child of this.children) {
      child.checkRefs(allDecls, errors);
    }
  }

  checkCalls(errors: CompilerError[], aiModules: Record<string, Module<any>>) {
    for (const child of this.children) {
      child.checkCalls(errors, aiModules);
    }
  }

  override addRefs(refs: Set<string>) {
    for (const child of this.children) {
      child.addRefs(refs);
    }
  }

  abstract trans(want: 'number' | 'signal', signals: string[]): string;
}

class Arg {
  constructor(
    readonly name: string,
    readonly expr: AExpr,
    readonly interval: ohm.Interval
  ) {}

  trans(signals: string[]) {
    return `${this.name}: ${this.expr.trans('signal', signals)}`;
  }
}

class Call extends AExpr {
  constructor(
    readonly name: string,
    readonly args: Arg[],
    interval: ohm.Interval
  ) {
    super(
      interval,
      args.map(a => a.expr)
    );
  }

  override checkCalls(errors: CompilerError[], aiModules: Record<string, Module<any>>) {
    super.checkCalls(errors, aiModules);
    const module = inlinedModules[this.name] || lib[this.name] || aiModules[this.name];
    if (!module) {
      errors.push(new CompilerError(`undeclared module: ${this.name}`, this.interval));
      return;
    }
    for (const { name } of this.args) {
      if (!module.defaultParamValues.hasOwnProperty(name)) {
        errors.push(
          new CompilerError(
            `${name} is not a valid argument for module ${this.name}`,
            this.interval
          )
        );
      }
    }
  }

  override trans(want: 'number' | 'signal', signals: string[]) {
    let call: string;
    if (inlinedModules.hasOwnProperty(this.name)) {
      const module = inlinedModules[this.name];
      const args = {} as Record<string, string>;
      for (const { name, expr } of this.args) {
        args[name] = expr.trans('number', signals);
      }
      call = module.codegen(args);
      if (want === 'signal') {
        const idx = signals.length;
        signals.push(`Signal.new(() => ${call})`);
        call = `tmp${idx}`;
      }
    } else {
      const args = this.args
        .map(({ name, expr }) => `${name}: ${expr.trans('signal', signals)}`)
        .join(', ');
      call = `_.${this.name}.new({ ${args} })`;
      const idx = signals.length;
      signals.push(call);
      call = `tmp${idx}`;
      if (want === 'number') {
        call = `${call}.value`;
      }
    }
    return call;
  }
}

class Ref extends AExpr {
  constructor(
    readonly name: string,
    interval: ohm.Interval
  ) {
    super(interval);
  }

  override addRefs(refs: Set<string>) {
    refs.add(this.name);
  }

  override checkRefs(allDecls: Decl[], errors: CompilerError[]) {
    if (
      getParamNum(this.name) == null && // "param123"
      !PARAM_NAMES.has(this.name) && // "A", "B", "C", "D"
      !builtInSignals.hasOwnProperty(this.name) && // "noise", "input", etc.
      !allDecls.some(d => d.name === this.name) // "left", "right", "out", etc.
    ) {
      errors.push(new CompilerError(`undeclared reference: ${this.name}`, this.interval));
    }
  }

  override trans(want: 'number' | 'signal', signals: string[]) {
    const n = getParamNum(this.name);
    const ref = n !== null ? `__param${n}` : `__${this.name}`;
    return want === 'signal' ? ref : `${ref}.value`;
  }
}

class ANumber extends AExpr {
  constructor(
    readonly value: number,
    interval: ohm.Interval
  ) {
    super(interval);
  }

  override trans(want: 'number' | 'signal') {
    const number = '' + this.value;
    return want === 'number' ? number : `Signal.scalar(${number})`;
  }
}

function getParamNum(name: string) {
  if (!(name.startsWith('param') && [...name.slice(5)].every(c => '0' <= c && c <= '9'))) {
    return null;
  }
  const n = parseInt(name.slice(5));
  return 0 <= n && n <= 127 ? n : null;
}

const s = grammar.createSemantics().addOperation<any>('toAst', {
  Prog(decls) {
    return new Prog(decls.toAst(), this.source);
  },
  Decl(n, _eq, e) {
    return new Decl(n.sourceString, e.toAst(), this.source);
  },
  ArrowExpr_send(r, _arrow, m, es) {
    return new Call(
      m.sourceString,
      [new Arg('input', r.toAst(), r.source), ...(es.child(0)?.toAst() ?? [])],
      this.source
    );
  },
  AddExpr_plus(x, _plus, y) {
    return new Call(
      '+',
      [new Arg('x', x.toAst(), x.source), new Arg('y', y.toAst(), y.source)],
      this.source
    );
  },
  AddExpr_minus(x, _minus, y) {
    return new Call(
      '-',
      [new Arg('x', x.toAst(), x.source), new Arg('y', y.toAst(), y.source)],
      this.source
    );
  },
  MulExpr_times(x, _times, y) {
    return new Call(
      '*',
      [new Arg('x', x.toAst(), x.source), new Arg('y', y.toAst(), y.source)],
      this.source
    );
  },
  MulExpr_div(x, _div, y) {
    return new Call(
      '/',
      [new Arg('x', x.toAst(), x.source), new Arg('y', y.toAst(), y.source)],
      this.source
    );
  },
  MulExpr_mod(x, _mod, y) {
    return new Call(
      '%',
      [new Arg('x', x.toAst(), x.source), new Arg('y', y.toAst(), y.source)],
      this.source
    );
  },
  NegExpr_neg(_minus, e) {
    return new Call('unary-', [new Arg('x', e.toAst(), e.source)], this.source);
  },
  SendExpr_send(r, m, es) {
    return new Call(
      m.sourceString,
      [new Arg('input', r.toAst(), r.source), ...(es.child(0)?.toAst() ?? [])],
      this.source
    );
  },
  PriExpr_call(n, es) {
    return new Call(n.sourceString, es.toAst(), this.source);
  },
  PriExpr_ref(n) {
    return new Ref(this.sourceString, this.source);
  },
  PriExpr_num(n) {
    return new ANumber(parseFloat(this.sourceString), this.source);
  },
  PriExpr_par(_oparen, e, _cparen) {
    return e.toAst();
  },
  Args(_oparen, es, _cparen) {
    return es.toAst();
  },
  Arg_nameAndExpr(n, _colon, e) {
    return new Arg(n.sourceString, e.toAst(), this.source);
  },
  Arg_nameIsExpr(n) {
    return new Arg(n.sourceString, new Ref(n.sourceString, this.source), this.source);
  },
  ident(_optDollar, _first, _rest) {
    return this.sourceString;
  },
  NonemptyListOf(x, _sep, xs) {
    return [x.toAst()].concat(xs.toAst());
  },
  EmptyListOf() {
    return [];
  },
  _iter(...children) {
    return children.map(c => c.toAst());
  },
});

export function parse(input: string): Prog {
  const errors: CompilerError[] = [];

  const mr = grammar.match(input);
  if (mr.failed()) {
    const expected = (mr as any)
      .getRightmostFailures()
      .map((f: any) => (f.type === 'string' ? `"${f.text}"` : f.text));
    if (expected.length > 1) {
      expected[expected.length - 1] = 'or ' + expected[expected.length - 1];
    }
    errors.push(new CompilerError(`expected ${expected.join(', ')}`, mr.getInterval()));
    throw new CompilerErrors(errors);
  }

  return s(mr).toAst() as Prog;
}

export function compile(
  input: string,
  aiModules: Record<string, Module<any>>
): { makeSignals: () => Signal[] } {
  const prog = parse(input);

  const errors: CompilerError[] = [];
  prog.checkDuplicateDeclarations(errors);
  prog.checkCalls(errors, aiModules);
  const refs = prog.checkRefs(errors);
  if (errors.length > 0) {
    throw new CompilerErrors(errors);
  }

  const code = prog.trans(refs);
  // console.log('compiled code:\n', code);

  return {
    makeSignals: () => evalCompiledCode(code, aiModules),
  };
}

function evalCompiledCode(code: string, aiModules: Record<string, Module<any>>): Signal[] {
  const _ = Object.create(lib);
  for (const [name, module] of Object.entries(aiModules)) {
    _[name] = module;
  }

  const __ = builtInSignals;
  const lazy = (makeSignal: () => Signal) => {
    let s: Signal | null = null;
    const force = () => {
      if (!s) {
        s = makeSignal();
      }
      return s;
    };
    const proxy = Signal.new({
      nextSample: (synth, inputs, frameIdx) => force().nextSample(synth, inputs, frameIdx),
      initialValue: 0, // can't call force() here because it may be recursive!
      noteOn: (voice, retriggered) => force().noteOn?.(voice, retriggered),
      noteOff: () => force().noteOff?.(),
    });
    (proxy as any).force = force;
    return proxy;
  };
  const ifZero = (x: number, y: number) => (x === 0 ? y : x);
  return new Function('Signal', '_', '__', 'lazy', 'ifZero', `return ${code};`)(
    Signal,
    _,
    __,
    lazy,
    ifZero
  );
}
