import {
  DEFAULT_INPUT_GAIN,
  INPUT_DEVICE_GAIN_KEY_PREFIX,
  LAST_INPUT_DEVICE_KEY,
  SAMPLE_RATE,
} from './constants';
import { Font } from './ui-constants';

let afterWebAudioInitializedFn: () => void;

export function afterWebAudioInitializedDo(fn: () => void) {
  afterWebAudioInitializedFn = fn;
}

export const context = new AudioContext({
  latencyHint: 'balanced',
  sampleRate: SAMPLE_RATE,
});

/** Bus before the DAC — both msynth instances and tape feed here so stacked voices don’t run away. */
export const masterCompressor = context.createDynamicsCompressor();
masterCompressor.connect(context.destination);

// @ts-ignore -- not a real error, see https://v3.vitejs.dev/guide/assets.html
import synthWorkletUrl from './msynth-worklet.ts?worker&url';
await context.audioWorklet.addModule(synthWorkletUrl);

// @ts-ignore -- not a real error, see https://v3.vitejs.dev/guide/assets.html
import tapeWorkletUrl from './tape-worklet.ts?worker&url';
await context.audioWorklet.addModule(tapeWorkletUrl);

let currentInputDeviceId: string | null = null;
let currentInputSource: MediaStreamAudioSourceNode | null = null;
let currentInputStream: MediaStream | null = null;
const inputConsumers: AudioNode[] = [];
const inputGainNode = context.createGain();
inputGainNode.gain.value = DEFAULT_INPUT_GAIN;
const inputAnalyserNode = context.createAnalyser();
inputAnalyserNode.fftSize = 512;
inputAnalyserNode.smoothingTimeConstant = 0.7;
const inputMeterTimeDomainData = new Float32Array(inputAnalyserNode.fftSize);
inputGainNode.connect(inputAnalyserNode);

export function getInputGain(): number {
  return inputGainNode.gain.value;
}

export function setInputGain(value: number): void {
  inputGainNode.gain.value = value;
  saveInputGain();
}

export function getInputLevelNormalized(floorDb = -96): number {
  const db = getInputLevelDb(floorDb);
  return (db - floorDb) / -floorDb;
}

function getInputLevelDb(floorDb = -96): number {
  const { rms } = getInputLevels();
  if (rms <= 0) {
    return floorDb;
  }
  const db = 20 * Math.log10(rms);
  return Math.max(db, floorDb);
}

function getInputLevels(): { rms: number; peak: number } {
  inputAnalyserNode.getFloatTimeDomainData(inputMeterTimeDomainData);

  let sumSq = 0;
  let peak = 0;
  for (let i = 0; i < inputMeterTimeDomainData.length; i++) {
    const v = inputMeterTimeDomainData[i];
    const abs = Math.abs(v);
    if (abs > peak) {
      peak = abs;
    }
    sumSq += v * v;
  }

  const rms = Math.sqrt(sumSq / inputMeterTimeDomainData.length);
  return { rms, peak };
}

export function registerInputConsumer(node: AudioNode): void {
  inputConsumers.push(node);
  inputGainNode.connect(node);
}

function showDevicePickerOverlay(): Promise<string | null> {
  return new Promise(async resolve => {
    const overlay = document.createElement('div');
    overlay.style.cssText = `
      position: fixed;
      inset: 0;
      z-index: 10000;
      display: flex;
      align-items: center;
      justify-content: center;
      background: rgba(0, 0, 0, 0.05);
      backdrop-filter: blur(3px);
      -webkit-backdrop-filter: blur(3px);
    `;
    const panel = document.createElement('div');
    panel.style.cssText = `
      width: 80%;
      max-width: 400px;
      border-radius: 8px;
      background: #fff;
      box-shadow: 0 20px 60px rgba(0,0,0,0.2);
      display: flex;
      flex-direction: column;
      overflow: hidden;
      padding: 20px;
      gap: 12px;
    `;

    const title = document.createElement('div');
    title.textContent = 'Select input device';
    title.style.cssText = `font: ${Font.button.cssFontString}; margin-bottom: 4px;`;
    panel.appendChild(title);

    const list = document.createElement('div');
    list.style.cssText = `display: flex; flex-direction: column; gap: 8px; max-height: 60vh; overflow-y: auto;`;
    panel.appendChild(list);

    const cancelBtn = document.createElement('button');
    cancelBtn.textContent = 'Cancel';
    cancelBtn.style.cssText = `font: ${Font.button.cssFontString}; margin-top: 8px; padding: 10px;`;
    cancelBtn.onclick = () => {
      overlay.remove();
      resolve(null);
    };
    panel.appendChild(cancelBtn);

    overlay.appendChild(panel);
    document.body.appendChild(overlay);

    const devices = await navigator.mediaDevices.enumerateDevices();
    const audioInputs = devices.filter(d => d.kind === 'audioinput');
    if (audioInputs.length === 0) {
      const msg = document.createElement('div');
      msg.textContent = 'No audio input devices found.';
      msg.style.color = '#666';
      list.appendChild(msg);
      return;
    }
    for (const d of audioInputs) {
      const button = document.createElement('button');
      button.textContent = d.label || `Device ${d.deviceId.slice(0, 8)}`;
      button.style.cssText = `font: ${Font.button.cssFontString}; padding: 10px; text-align: left;`;
      button.onclick = () => {
        overlay.remove();
        resolve(d.deviceId);
      };
      list.appendChild(button);
    }
  });
}

/** Opens the given input device and wires it to the input chain. Stops `releaseStream` after a successful open. */
async function connectInputWithDeviceId(
  deviceId: string,
  releaseStream: MediaStream | null
): Promise<MediaStreamAudioSourceNode | null> {
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      audio: {
        deviceId: { exact: deviceId },
        autoGainControl: false,
        echoCancellation: false,
      },
    });
    if (releaseStream) {
      releaseStream.getTracks().forEach(t => t.stop());
    }
    if (currentInputSource) {
      currentInputSource.disconnect();
      currentInputSource = null;
    }
    if (currentInputStream) {
      currentInputStream.getTracks().forEach(t => t.stop());
      currentInputStream = null;
    }
    currentInputStream = stream;
    currentInputSource = context.createMediaStreamSource(stream);
    currentInputSource.connect(inputGainNode);
    for (const worklet of inputConsumers) {
      inputGainNode.connect(worklet);
    }
    currentInputDeviceId = deviceId;
    loadInputGain();
    localStorage.setItem(LAST_INPUT_DEVICE_KEY, deviceId);
    return currentInputSource;
  } catch (err) {
    console.warn('Failed to get user media:', err);
    return null;
  }
}

export async function selectInputDevice(): Promise<MediaStreamAudioSourceNode | null> {
  const permissionStream = await navigator.mediaDevices.getUserMedia({ audio: true });

  const deviceId = await showDevicePickerOverlay();
  if (deviceId === null) {
    permissionStream.getTracks().forEach(t => t.stop());
    return null;
  }

  const node = await connectInputWithDeviceId(deviceId, permissionStream);
  if (!node) {
    permissionStream.getTracks().forEach(t => t.stop());
  }
  return node;
}

async function tryRestoreLastInputDevice(): Promise<void> {
  let savedId: string | null;
  try {
    savedId = localStorage.getItem(LAST_INPUT_DEVICE_KEY);
  } catch {
    return;
  }
  if (!savedId) {
    return;
  }

  let permissionStream: MediaStream | null = null;
  try {
    permissionStream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const node = await connectInputWithDeviceId(savedId, permissionStream);
    if (!node) {
      localStorage.removeItem(LAST_INPUT_DEVICE_KEY);
      permissionStream.getTracks().forEach(t => t.stop());
    }
  } catch (err) {
    console.warn('Could not restore last input device:', err);
    permissionStream?.getTracks().forEach(t => t.stop());
  }
}

let webAudioState: 'need initialization' | 'initializing' | 'ready' = 'need initialization';

export function ensureWebAudioInitialized() {
  if (webAudioState === 'need initialization') {
    webAudioState = 'initializing';
    console.info('initializing web audio');
    afterWebAudioInitializedFn?.();
    webAudioState = 'ready';
    console.info('web audio ready');
    tryRestoreLastInputDevice();
  }

  // When the iPad is turned off then turned back on, the audio context gets suspended.
  // We need to resume it, and that only works when done in response to a user interaction.
  if (context.state === 'suspended' || context.state === 'interrupted') {
    // Note: no await on purpose!
    console.info('resuming web audio!');
    context.resume();
  }
}

function loadInputGain() {
  inputGainNode.gain.value = DEFAULT_INPUT_GAIN;

  if (!currentInputDeviceId) {
    return;
  }

  const text = localStorage.getItem(INPUT_DEVICE_GAIN_KEY_PREFIX + currentInputDeviceId);
  if (!text) {
    return;
  }

  const v = parseFloat(text);
  if (!Number.isFinite(v) || v < 0) {
    return;
  }

  inputGainNode.gain.value = v;
}

function saveInputGain(): void {
  if (currentInputDeviceId) {
    localStorage.setItem(INPUT_DEVICE_GAIN_KEY_PREFIX + currentInputDeviceId, '' + getInputGain());
  }
}
